define('taoMediaManager/qtiCreator/editor/interactionsPanel',['lodash', 'i18n', 'taoQtiItem/qtiCreator/editor/interactionsToolbar', 'taoQtiItem/qtiCreator/helper/panel'], function (_, __, interactionsToolbar, panel) {
  'use strict';
  return function setUpInteractionPanel($container) {
    var tagTitles = {
      inlineInteractions: __('Inline Interactions')
    };
    var interactions = {
      _container: {
        label: __('Text Block'),
        icon: 'icon-font',
        description: __('Block contains the content (stimulus) of the item such as text or image. It is also required for Inline Interactions.'),
        short: __('Block'),
        qtiClass: '_container',
        tags: [tagTitles.inlineInteractions, 'text'],
        group: __('inline-interactions')
      }
    };
    interactionsToolbar.create($container, interactions);
    panel.initSidebarAccordion($container);
    panel.toggleInlineInteractionGroup();
  };
});
