define('taoMediaManager/controller/authoring',['i18n', 'lodash', 'jquery', 'uri', 'taoMediaManager/qtiCreator/component/sharedStimulusAuthoring', 'ui/feedback', 'util/url', 'core/dataProvider/request', 'core/logger'], function (__, _, $, uri, sharedStimulusAuthoringFactory, feedback, urlUtil, request, loggerFactory) {
  'use strict';

  var logger = loggerFactory('taoMediaManager/authoring');
  var serviceController = 'SharedStimulus';
  var serviceExtension = 'taoMediaManager';
  var manageMediaController = {
    start() {
      var $panel = $('#panel-authoring');
      var assetDataUrl = urlUtil.route('get', serviceController, serviceExtension);
      var assetDataStyles = urlUtil.route('getStylesheets', 'SharedStimulusStyling', serviceExtension);
      var assetId = uri.decode($panel.attr('data-id'));
      var previewEnabled = false;
      request(assetDataUrl, {
        id: assetId
      }).then(response => {
        if (response.permissions.includes('READ')) {
          previewEnabled = true;
        }
      }).then(() => {
        sharedStimulusAuthoringFactory($panel, {
          properties: {
            uri: $panel.attr('data-uri'),
            id: assetId,
            assetDataUrl,
            assetDataStyles,
            fileUploadUrl: urlUtil.route('upload', 'ItemContent', 'taoItems'),
            fileDeleteUrl: urlUtil.route('delete', 'ItemContent', 'taoItems'),
            fileDownloadUrl: urlUtil.route('download', 'ItemContent', 'taoItems'),
            fileExistsUrl: urlUtil.route('fileExists', 'ItemContent', 'taoItems'),
            getFilesUrl: urlUtil.route('files', 'ItemContent', 'taoItems'),
            baseUrl: urlUtil.route('getFile', 'MediaManager', 'taoMediaManager', {
              uri: ''
            }),
            path: 'taomedia://mediamanager/',
            root: 'mediamanager',
            lang: 'en-US',
            previewEnabled: previewEnabled,
            loadCssUrl: urlUtil.route('load', 'SharedStimulusStyling', 'taoMediaManager'),
            saveCssUrl: urlUtil.route('save', 'SharedStimulusStyling', 'taoMediaManager'),
            downloadCssUrl: urlUtil.route('loadStylesheet', 'SharedStimulusStyling', 'taoMediaManager')
          }
        }).on('success', () => {
          feedback().success(__('Your passage is saved'));
        }).on('error', err => {
          if (!_.isUndefined(err.message)) {
            feedback().error(err.message);
          }
          logger.error(err);
        });
      });
    }
  };
  return manageMediaController;
});
