define('taoMediaManager/previewer/adapter/item/qtiSharedStimulusItem',['lodash', 'core/logger', 'taoMediaManager/previewer/component/qtiSharedStimulusItem', 'ui/feedback'], function (_, loggerFactory, qtiItemPreviewerFactory, feedback) {
  'use strict';

  var logger = loggerFactory('taoMediaManager/previewer');
  var defaultPlugins = [{
    module: 'taoQtiTestPreviewer/previewer/plugins/controls/close',
    bundle: 'taoQtiTestPreviewer/loader/qtiPreviewer.min',
    category: 'controls'
  }, {
    module: 'taoQtiTestPreviewer/previewer/plugins/tools/scale/scale',
    bundle: 'taoQtiTestPreviewer/loader/qtiPreviewer.min',
    category: 'tools'
  }, {
    module: 'taoQtiTest/runner/plugins/tools/itemThemeSwitcher/itemThemeSwitcher',
    bundle: 'taoQtiTest/loader/testPlugins.min',
    category: 'tools'
  }];
  return {
    name: 'qtiSharedStimulusItem',
    init(sharedStimulusId) {
      var config = arguments.length > 1 && arguments[1] !== undefined ? arguments[1] : {};
      config.itemUri = sharedStimulusId;
      config.plugins = Array.isArray(config.plugins) ? [...defaultPlugins, ...config.plugins] : defaultPlugins;
      return qtiItemPreviewerFactory(window.document.body, config).on('error', function (err) {
        if (!_.isUndefined(err.message)) {
          feedback().error(err.message);
        }
        logger.error(err);
      });
    }
  };
});
