define('taoMediaManager/qtiCreator/widgets/static/text/states/Active',['jquery', 'taoQtiItem/qtiCreator/widgets/states/factory', 'taoMediaManager/qtiCreator/widgets/static/states/Active', 'taoMediaManager/qtiCreator/editor/ckEditor/htmlEditor', 'taoQtiItem/qtiCreator/editor/gridEditor/content', 'taoQtiItem/qtiCreator/widgets/helpers/formElement', 'tpl!taoMediaManager/qtiCreator/tpl/forms/static/text', 'taoMediaManager/qtiCreator/editor/styleEditor/styleEditor', 'taoMediaManager/qtiCreator/editor/styleEditor/fontSelector', 'taoMediaManager/qtiCreator/editor/styleEditor/colorSelector', 'taoMediaManager/qtiCreator/editor/styleEditor/fontSizeChanger'], function ($, stateFactory, Active, htmlEditor, content, formElement, formTpl, styleEditor, fontSelector, colorSelector, fontSizeChanger) {
  'use strict';

  var wrapperCls = 'custom-text-box';
  var TextActive = stateFactory.extend(Active, function () {
    this.buildStylesEditor();
    this.buildEditor();
    this.initForm();
  }, function () {
    this.destroyEditor();
    this.destroyStylesEditor();
    this.widget.$form.empty();
  });
  TextActive.prototype.buildEditor = function () {
    var widget = this.widget;
    var $editableContainer = widget.$container;
    var container = widget.element;
    var changeCallback = content.getChangeCallback(container);
    $editableContainer.attr('data-html-editable-container', true);
    if (!htmlEditor.hasEditor($editableContainer)) {
      htmlEditor.buildEditor($editableContainer, {
        change: function change(data) {
          changeCallback.call(this, data);
          if (!data) {
            widget.$form.find('[name="textBlockCssClass"]').val('');
          }
        },
        blur: function blur() {
          widget.changeState('sleep');
        },
        data: {
          widget: widget,
          container: container
        }
      });
    }
  };
  TextActive.prototype.buildStylesEditor = function () {
    var widget = this.widget;
    var $editableContainer = widget.$container;
    var $block = $editableContainer.find(".".concat(wrapperCls));
    if (!$block.length) {
      $block = widget.$container.find('[data-html-editable="true"]').wrapInner('<div />').children();
      var hashClass = styleEditor.generateHashClass();
      $block.attr('class', "".concat(wrapperCls, " ").concat(hashClass));
    } else {
      var blockCls = widget.$container.find(".".concat(wrapperCls)).attr('class').split(' ');
      var _hashClass = blockCls.find(className => /^tao-*/.test(className));
      if (_hashClass) {
        styleEditor.setHashClass(_hashClass);
      } else {
        _hashClass = styleEditor.generateHashClass();
        $block.addClass(_hashClass);
      }
    }
    var $textEditor = $('#item-editor-text-property-bar');
    fontSelector($textEditor);
    colorSelector($textEditor);
    fontSizeChanger($textEditor);
  };
  TextActive.prototype.destroyEditor = function () {
    htmlEditor.destroyEditor(this.widget.$container);
  };
  TextActive.prototype.destroyStylesEditor = function () {
    var hashClass = styleEditor.getHashClass();
    var $block = this.widget.$container.find(".".concat(wrapperCls));
    var textBlockCssClass = ($block.attr('class') || '').replace(wrapperCls, '').replace(hashClass, '').trim();
    var styles = styleEditor.getStyle();
    var regex = new RegExp(hashClass);
    if (!textBlockCssClass && !Object.keys(styles).find(selector => regex.test(selector))) {
      $block.children().unwrap();
    }
  };
  TextActive.prototype.initForm = function () {
    var widget = this.widget;
    var $form = widget.$form;
    var blockCls = widget.$container.find(".".concat(wrapperCls)).attr('class');
    var hashClass = styleEditor.getHashClass();
    $form.html(formTpl({
      textBlockCssClass: (blockCls || '').replace(wrapperCls, '').replace(hashClass, '').trim()
    }));
    formElement.initWidget($form);
    formElement.setChangeCallbacks($form, widget.element, {
      textBlockCssClass: function textBlockCssClass(element, value) {
        var $block = widget.$container.find(".".concat(wrapperCls));
        value = value.trim();
        if (value === wrapperCls) {
          value = '';
        }
        if (value) {
          if (!$block.length) {
            $block = widget.$container.find('[data-html-editable="true"]').wrapInner('<div />').children();
          }
          $block.attr('class', "".concat(wrapperCls, " ").concat(value));
        }
      }
    });
  };
  return TextActive;
});
