define('taoMediaManager/qtiCreator/widgets/helpers/content',['jquery', 'lodash', 'taoMediaManager/qtiCreator/helper/creatorRenderer', 'taoQtiItem/qtiCreator/model/helper/container', 'taoQtiItem/qtiCreator/editor/gridEditor/content'], function ($, _, creatorRenderer, containerHelper, gridContentHelper) {
  'use strict';
  var contentHelper = {};
  contentHelper.createElements = function createElements(container, $container, data, callback) {
    var $dummy = $('<div>').html(data);
    containerHelper.createElements(container, gridContentHelper.getContent($dummy), function (newElts) {
      creatorRenderer.get().load(function () {
        _.forEach(newElts, function (serial) {
          var $placeholder, $widget, widget;
          $placeholder = $container.find(".widget-box[data-new][data-qti-class=".concat(serial.qtiClass, "]"));
          serial.setRenderer(this);
          serial.render($placeholder);
          serial.postRender();
          widget = serial.data('widget');
          $widget = widget.$original;
          $widget.trigger('contentChange.gridEdit');
          if (_.isFunction(callback)) {
            callback(widget);
          }
        }.bind(this));
      }, this.getUsedClasses());
    });
  };
  contentHelper.changeInnerWidgetState = function _changeInnerWidgetState(outerWidget, state) {
    var selector = [];
    _.forEach(['img', 'math', 'object', 'include'], function (qtiClass) {
      selector.push("[data-html-editable] .widget-".concat(qtiClass));
    });
    outerWidget.$container.find(selector.join(',')).each(function () {
      var innerWidget = $(this).data('widget');
      if (innerWidget) {
        innerWidget.changeState(state);
      }
    });
  };
  return contentHelper;
});
