define('taoMediaManager/qtiCreator/widgets/static/figure/Widget',['jquery', 'lodash', 'context', 'taoQtiItem/qtiCreator/widgets/static/Widget', 'taoMediaManager/qtiCreator/widgets/static/figure/states/states', 'taoQtiItem/qtiCreator/widgets/static/helpers/widget', 'tpl!taoQtiItem/qtiCreator/tpl/toolbars/media', 'taoQtiItem/qtiCreator/widgets/static/helpers/inline', 'ui/mediaEditor/plugins/mediaAlignment/helper'], function ($, _, context, Widget, states, helper, toolbarTpl, inlineHelper, alignmentHelper) {
  'use strict';

  var FigureWidget = Widget.clone();
  var DISABLE_FIGURE_WIDGET = context.featureFlags['FEATURE_FLAG_DISABLE_FIGURE_WIDGET'];
  FigureWidget.initCreator = function initCreator(options) {
    var figure = this.element;
    var img = _.find(figure.getBody().elements, elem => elem.is('img'));
    this.registerStates(states);
    Widget.initCreator.call(this);
    inlineHelper.togglePlaceholder(this);
    alignmentHelper.initAlignment(this);
    inlineHelper.checkFileExists(this, img, 'src', options.baseUrl);
    $('#item-editor-scope').on("filedelete.resourcemgr.".concat(this.element.serial), (e, src) => {
      if (this.getAssetManager().resolve(img.attr('src')) === this.getAssetManager().resolve(src)) {
        img.attr('src', '');
        inlineHelper.togglePlaceholder(this);
      }
    });
  };
  FigureWidget.destroy = function destroy() {
    $('#item-editor-scope').off(".".concat(this.element.serial));
  };
  FigureWidget.getRequiredOptions = function () {
    return ['baseUrl', 'uri', 'lang', 'mediaManager', 'assetManager'];
  };
  FigureWidget.buildContainer = function buildContainer() {
    if (DISABLE_FIGURE_WIDGET || this.element.attr('showFigure')) {
      helper.buildBlockContainer(this);
    } else {
      helper.buildInlineContainer(this);
    }
    var img = _.find(this.element.getBody().elements, elem => elem.is('img'));
    var $img = this.$original.find('img');
    if ($img.length) {
      this.$container.css({
        width: img.attr('width')
      });
      $img.attr('width', '100%');
      $img.removeAttr('style');
    }
    return this;
  };
  FigureWidget.createToolbar = function createToolbar() {
    helper.createToolbar(this, toolbarTpl);
    return this;
  };
  return FigureWidget;
});
